+   private static String validateZipEntryName(String name) throws IOException
+   {
+      if (name == null)
+      {
+         throw new IOException("Zip entry name cannot be null");
+      }
+      
+      // Normalize the path
+      String normalized = FilenameUtils.normalize(name);
+      if (normalized == null)
+      {
+         throw new IOException("Invalid zip entry name: " + name);
